{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Household income at or below 200% of the federal poverty level. Example from Mid-Nebraska (likely recent): For 8-person household, $105,440; adds $10,760 per additional person. Exact amounts revised annually; SSI, TANF, or LIHEAP recipients automatically eligible regardless of income.[2][3][4][6]",
    "asset_limits": "No asset limits mentioned in program policies.[2]",
    "other_requirements": ["Occupied by eligible family (owner or renter with landlord permission, including single-family, multi-family, mobile homes, frame homes)", "Dwelling must meet structure eligibility (e.g., weatherization needs)", "Automatic eligibility if household received SSI, TANF cash assistance (Title IV/XVI), or LIHEAP in current or prior 12 months.[2][1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free energy-efficiency improvements including sidewall/attic insulation, caulking/weatherstripping, glass repair, furnace repair/replacement (home-owned only), indoor air quality checks, combustion safety, carbon monoxide testing, health/safety measures; certified inspection post-work.[1][3][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Varies by region/provider (e.g., Douglas County: call 402-342-8232 or unitedwaymidlands.org/weatherization; United Way Midlands: 402-444-6666 opt 6, DCWAP@uwmidlands.org, mail to 1229 Millwork Ave Suite 402 Omaha NE 68102-4277; Northeast Nebraska: online Weatherization Application at nencap.org; Mid-Nebraska: contact communityactionmidne.com; statewide contact via dee.nebraska.gov or catenergy.ne.gov).[1][3][5]"],
    "processing_time": "Not specified; re-verify income if work not started within 12 months.[2]",
    "waitlist": "Regional waitlists exist (e.g., Northeast Nebraska 14-county area may have waits as they weatherize ~100 homes/year).[3]",
    "forms": ["Weatherization Application (name varies by provider, e.g., Northeast Nebraska Weatherization Application; no universal form number).[3]"],
    "documents": ["Proof of income, SSI/TANF/LIHEAP receipt if claiming automatic eligibility, landlord permission if renting (inferred from policies); prepare household size and 12-month income details.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered regionally by local providers (e.g., Douglas County via United Way/OPPD, Northeast 14 counties via NENCAP, Mid-Nebraska 27 south central counties).[1][3][4][5]",
    "regional_variations": "Different subgrantees/providers per region handle applications, services, wait times; priority same statewide but capacity varies (e.g., ~100 homes/year in Northeast).[2][3][4]",
    "offices_or_providers": ["United Way of the Midlands (Douglas County/Omaha), Northeast Nebraska Community Action Partnership (14 counties: Antelope, Burt, Cedar, Cuming, Dakota, Dixon, Dodge, Knox, Madison, Pierce, Stanton, Thurston, Washington, Wayne), Community Action Partnership of Mid-Nebraska (27 south central counties), Nebraska Dept of Environment and Energy (state admin).[1][3][4][5]"]
  },
  "official_source": "https://dee.nebraska.gov/sites/default/files/publications/22-044-Final_WX_Full_Policies_and_Procedures_Manual.pdf",
  "gotchas": ["Must meet both client income AND dwelling/structure eligibility; automatic eligibility limited to SSI/TANF/LIHEAP recipients in specific timeframes (current year or prior 12 months); renters need landlord permission; regional providers mean contacting wrong one delays process; priority to elderly (60+), disabled, young children—not guaranteed service; waitlists common in lower-capacity areas; income re-verified after 12 months if delayed.[1][2][3][4]"],
  "data_shape_notes": "Administered by regional subgrantees with statewide uniform eligibility (200% FPL or auto-qualifiers) but varying application contacts, capacities, wait times; priority tiers favor elderly/disabled; no age minimum but elderly prioritized.[2][3][4]"
}

{
  "name": "Nebraska SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare-eligible individuals, families, and caregivers[1][2][6]",
    "asset_limits": "No asset limits; services are free and not restricted by resources[1][2][4][6]",
    "other_requirements": ["Must be eligible for Medicare or a family member/caregiver of a Medicare beneficiary[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling on Medicare eligibility/benefits, Medicare Supplement Insurance, Prescription Drug Plans, Medicare Advantage Plans, Extra Help for prescription costs, employer/retiree insurance; assistance applying for programs to help pay Medicare/drug costs for those with limited income/resources; Medicare fraud prevention/education via SMP; personalized problem-solving, outreach, and community speaking[1][2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-234-7119 (toll-free, statewide, hours 8:00 am - 4:30 pm)[1][2][3][7]", "Website: https://doi.nebraska.gov/consumer/nebraska-ship-smp or https://doi.nebraska.gov/ship-smp[2][3][4][7]", "Email: doi.ship@nebraska.gov[4]", "In-person: Through statewide network of certified counselors and local partners like Area Agencies on Aging (e.g., Northeast Nebraska AAA, Volunteers Assisting Seniors in Omaha, West Central Nebraska AAA in North Platte)[1][4]"],
    "processing_time": "No formal application or processing; counseling arranged directly upon contact[1][2]",
    "waitlist": null,
    "forms": ["No specific forms required; may assist with applications for Extra Help or Medicare Savings Programs during counseling[4]"],
    "documents": ["No documents needed to start; for assistance with Extra Help or cost programs, prepare income/resource details if applicable[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Nebraska Medicare residents[1][2][3]",
    "regional_variations": "Delivered via statewide network with local partners like Area Agencies on Aging; specific offices include Northeast Nebraska AAA (contracts for local help), Volunteers Assisting Seniors (Omaha: 900 S. 74th Plaza, Suite 403), West Central Nebraska AAA (North Platte: 115 North Vine Street), and others in Kearney; no differences in services, eligibility, or wait times noted[1][4]",
    "offices_or_providers": ["Nebraska Department of Insurance (PO Box 95087, Lincoln NE 68509-5087)[3]", "Local: Northeast Nebraska AAA, Volunteers Assisting Seniors (Omaha), West Central Nebraska AAA (North Platte), Kearney office[1][4]"]
  },
  "official_source": "https://doi.nebraska.gov/consumer/nebraska-ship-smp",
  "gotchas": ["Counselors do not recommend specific policies, companies, or agents—only provide unbiased information[1][2]", "Not an insurance seller or endorser; focuses on education and fraud prevention[1][2][4]", "Separate from hospital FLEX SHIP grants (unrelated rural health funding)[5]", "Volunteers and paid staff provide services; anyone with Medicare questions (beneficiaries, relatives, providers) can call[1][2]"],
  "data_shape_notes": "no income or asset test; free counseling service for Medicare navigation via statewide counselor network and local AAA partners; no formal enrollment—contact to arrange session"
}

{
  "name": "Aging & Disability Resource Center Act",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits stated in the Act; eligibility is open to persons aged 60+ or with disabilities of any age, family members, caregivers, advocates, and providers. For linked programs like Medicaid AD Waiver, income must meet Medicaid requirements (not detailed here with dollar amounts), and functional need for Nursing Facility Level of Care is required.[1][2][3][5][6]",
    "asset_limits": "No asset limits under the Act itself. For AD Waiver, home equity limit of $752,000 in 2026 (exempt if spouse or minor/permanently disabled child lives there); other exemptions may apply per Medicaid rules.[1]",
    "other_requirements": ["Nebraska resident", "For full long-term care access via ADRC, often requires Nursing Facility Level of Care (NFLOC) assessed via interRAI-HC tool: limited functioning in at least 3 ADLs (e.g., toileting, bathing) plus risk factor/medical condition/limited cognition, or 1 ADL limitation with risk and cognition issues", "Be eligible for Nebraska Medicaid for HCBS waivers accessed through ADRC", "SSN required for assistance programs", "Responsible for relative financial support per rules", "Blind/disabled determination by SSA for some aid categories[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive information on long-term care programs/options/financing/providers; options counseling; assistance accessing/applying for public benefits; single point of entry to publicly supported long-term care; identification of unmet needs with recommendations; person-centered transition support. Links to services like AD Waiver (in-home care, personal care, homemaker, respite) but does not directly provide funded services—facilitates access.[5][6][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Aging and Disability Resource Center (ADRC) by phone or in-person (regional numbers via area agencies on aging, e.g., Northeast Nebraska AAA at nenaaa.com)", "Online via dhhs.ne.gov for linked waivers", "Phone for assessment scheduling (DDD calls within 14 days of Medicaid eligibility check)", "In-person at community-based ADRC sites coordinated by area agencies on aging[3][6]"],
    "processing_time": "For linked AD Waiver: Medicaid check immediate, Level of Care call within 14 days[3]",
    "waitlist": "Not specified for ADRC core services; may apply to specific waivers accessed via ADRC[3]",
    "forms": ["AD Assessment (brochure/process for needs assessment)", "Medicaid application for waivers[3]"],
    "documents": ["Proof of residency", "SSN", "Medicaid eligibility docs", "Medical documentation for disability/NFLOC (e.g., physician/psychologist reports for developmental disability)", "Income/resource proof for linked programs[1][2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Community-based via local area agencies on aging; serves all Nebraska but access through regional centers",
    "regional_variations": "Delivered by local providers/area agencies on aging (e.g., Northeast Nebraska AAA, Western Community AAA); counties served vary (e.g., Douglas County specific); partnerships differ by region[4][6][7]",
    "offices_or_providers": ["Area Agencies on Aging (e.g., nenaaa.com for Northeast, wcnaaa.org for Western), DHHS DDD for waivers[3][6][8]"]
  },
  "official_source": "https://nebraskalegislature.gov/laws/statutes.php?statute=68-1116",
  "gotchas": ["Not a direct service/funding program—it's an information, counseling, and access hub; must qualify separately for Medicaid waivers (e.g., AD Waiver) for actual in-home services", "Age 60+ or any-age disability, but family/caregivers also eligible for info", "NFLOC required for waiver services, assessed via interRAI-HC—not automatic", "Regional delivery means contacting local ADRC, not centralized state office", "Home equity limit applies to AD Waiver ($752,000 in 2026), often missed[1][5]"],
  "data_shape_notes": "No income/asset test for core ADRC info services; regional via area agencies on aging; facilitates access to tiered waivers (e.g., AD Waiver) with NFLOC and Medicaid reqs; open to caregivers/family"
}
